# scripts/generate_capacity_report.py
import argparse, csv, json, os, sys
from pathlib import Path


def read_locust_stats(results_dir):
    """Read locust_stats_history.csv (one row per 2s tick)."""
    history_file = Path(results_dir) / "locust_stats_history.csv"
    rows = []
    with open(history_file) as f:
        for row in csv.DictReader(f):
            rows.append({
                "timestamp": float(row["Timestamp"]),
                "user_count": int(row["User count"]),
                "requests_per_s": float(row.get("Requests/s", 0)),
                "failures_per_s": float(row.get("Failures/s", 0)),
                "p95_ms": float(row.get("95%", 0)),
                "p99_ms": float(row.get("99%", 0)),
            })
    return rows


def summarize_by_user_band(rows, band_width=50):
    """Group rows into user-count bands and compute p95 per band."""
    from collections import defaultdict
    bands = defaultdict(list)
    for r in rows:
        band = (r["user_count"] // band_width) * band_width
        bands[band].append(r["p95_ms"])

    return {
        band: {
            "p95_median_ms": sorted(samples)[len(samples) // 2],
            "sample_count": len(samples),
        }
        for band, samples in sorted(bands.items())
    }


def find_safe_limit(band_summary, slo_ms=8000):
    safe = 0
    for users, stats in sorted(band_summary.items()):
        if stats["p95_median_ms"] <= slo_ms:
            safe = users
        else:
            break
    return safe


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--results-dir", required=True)
    parser.add_argument("--output", required=True)
    parser.add_argument("--slo-ms", type=int, default=8000)
    args = parser.parse_args()

    rows = read_locust_stats(args.results_dir)
    bands = summarize_by_user_band(rows)
    safe_limit = find_safe_limit(bands, args.slo_ms)

    # Also read the capacity_result.json written by the shape
    shape_result_path = Path(args.results_dir) / "capacity_result.json"
    shape_result = {}
    if shape_result_path.exists():
        with open(shape_result_path) as f:
            shape_result = json.load(f)

    report = {
        "safe_concurrency_limit": safe_limit,
        "slo_threshold_ms": args.slo_ms,
        "shape_reported_limit": shape_result.get("safe_limit_users"),
        "band_summary": bands,
        "passed": safe_limit >= 300,  # 1.5× the 200-user production target
    }

    os.makedirs(os.path.dirname(args.output), exist_ok=True)
    with open(args.output, "w") as f:
        json.dump(report, f, indent=2)

    print(f"Safe concurrency limit: {safe_limit} users (SLO: {args.slo_ms}ms p95)")
    print(f"Capacity gate: {'PASS' if report['passed'] else 'FAIL'}")

    if not report["passed"]:
        sys.exit(1)


if __name__ == "__main__":
    main()
